attributes.cssVariables:
:root {
  --blog-color-bg: #0d0d12;
  --blog-color-text: #f5f5f7;
  --blog-color-body: #d4d4dc;
  --blog-color-muted: #b8b8c0;
  --blog-color-subtle: #a0a0aa;
  --blog-color-faint: #707078;
  --blog-color-placeholder: #505058;
  --blog-color-thumb-bg: #1f1f28;
  --blog-color-divider: #2a2a33;
  --blog-color-accent: #ff2d92;
  --blog-color-card-bg: #16161d;
  --blog-font-family: 'JetBrains Mono', 'Fira Code', 'Menlo', monospace;
  --blog-font-headline: 700 3rem/1.1 var(--blog-font-family);
  --blog-font-display-l: 700 2.2rem/1.1 var(--blog-font-family);
  --blog-font-display-m: 700 1.7rem/1.15 var(--blog-font-family);
  --blog-font-name: 700 1.25rem/1.2 var(--blog-font-family);
  --blog-font-h2: 700 1.45rem/1.25 var(--blog-font-family);
  --blog-font-h3: 600 1.1rem/1.3 var(--blog-font-family);
  --blog-font-subtitle: 400 1rem/1.55 var(--blog-font-family);
  --blog-font-pullquote: 600 1.2rem/1.5 var(--blog-font-family);
  --blog-font-body: 400 0.95rem/1.75 var(--blog-font-family);
  --blog-font-body-sm: 400 0.85rem/1.65 var(--blog-font-family);
  --blog-font-meta: 600 0.7rem/1 var(--blog-font-family);
  --blog-font-eyebrow: 700 0.7rem/1 var(--blog-font-family);
  --blog-tracking-meta: 0.12em;
  --blog-tracking-eyebrow: 0.2em;
  --blog-tracking-tight: 0;
  --blog-tracking-tighter: 0;
  --blog-reading-max: 680px;
  --blog-subtitle-max: 720px;
  --blog-headline-max: 860px;
  --blog-canvas-max: 1100px;
  --blog-radius-md: 2px;
  --blog-radius-pill: 2px;
  --blog-shadow-card: 0 0 0 1px #2a2a33;
  --blog-shadow-card-hover: 0 0 0 1px #ff2d92, 0 8px 24px rgba(255, 45, 146, 0.18);
  --blog-shadow-portrait: 0 0 0 1px #2a2a33;
}
